package main

import (
    "database/sql"
    "fmt"
    "log"

    _ "github.com/mattn/go-sqlite3"
)

type Player struct {
    ID     int
    Name   string
    Health int
    Attack int
    Level  int
}

type PlayerRepo struct {
    db *sql.DB
}

func NewPlayerRepo(db *sql.DB) *PlayerRepo {
    return &PlayerRepo{db: db}
}

// ---- Create ----
func (r *PlayerRepo) Create(name string, health, attack, level int) (Player, error) {
    result, err := r.db.Exec(
        "INSERT INTO players (name, health, attack, level) VALUES (?, ?, ?, ?)",
        name, health, attack, level,
    )
    if err != nil {
        return Player{}, err
    }

    id, err := result.LastInsertId()
    if err != nil {
        return Player{}, err
    }

    return r.GetByID(int(id))
}

// ---- Read (all) ----
func (r *PlayerRepo) GetAll() ([]Player, error) {
    rows, err := r.db.Query("SELECT id, name, health, attack, level FROM players")
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    players := []Player{}
    for rows.Next() {
        var p Player
        err := rows.Scan(&p.ID, &p.Name, &p.Health, &p.Attack, &p.Level)
        if err != nil {
            return nil, err
        }
        players = append(players, p)
    }

    return players, nil
}

// ---- Read (one) ----
func (r *PlayerRepo) GetByID(id int) (Player, error) {
    var p Player
    err := r.db.QueryRow(
        "SELECT id, name, health, attack, level FROM players WHERE id = ?",
        id,
    ).Scan(&p.ID, &p.Name, &p.Health, &p.Attack, &p.Level)

    return p, err
}

// ---- Update ----
func (r *PlayerRepo) Update(id int, name string, health, attack, level int) (Player, error) {
    _, err := r.db.Exec(
        "UPDATE players SET name = ?, health = ?, attack = ?, level = ? WHERE id = ?",
        name, health, attack, level, id,
    )
    if err != nil {
        return Player{}, err
    }

    return r.GetByID(id)
}

// ---- Delete ----
func (r *PlayerRepo) Delete(id int) error {
    _, err := r.db.Exec("DELETE FROM players WHERE id = ?", id)
    return err
}

func main() {
    db, err := sql.Open("sqlite3", "./crud.db")
    if err != nil {
        log.Fatal(err)
    }
    defer db.Close()

    // ---- Create table ----
    _, err = db.Exec(`CREATE TABLE IF NOT EXISTS players (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL,
        health INTEGER DEFAULT 100,
        attack INTEGER DEFAULT 10,
        level INTEGER DEFAULT 1
    )`)
    if err != nil {
        log.Fatal(err)
    }

    repo := NewPlayerRepo(db)

    // ---- CREATE ----
    fmt.Println("=== CREATE ===")
    p1, _ := repo.Create("Hero", 100, 20, 5)
    fmt.Printf("Created: %+v\n", p1)

    p2, _ := repo.Create("Aragorn", 120, 25, 8)
    fmt.Printf("Created: %+v\n", p2)

    // ---- READ ----
    fmt.Println("\n=== READ ===")
    players, _ := repo.GetAll()
    fmt.Println("All players:")
    for _, p := range players {
        fmt.Printf("  %+v\n", p)
    }

    p, _ := repo.GetByID(1)
    fmt.Printf("\nPlayer with ID 1: %+v\n", p)

    // ---- UPDATE ----
    fmt.Println("\n=== UPDATE ===")
    p, _ = repo.Update(1, "Hero the Brave", 150, 25, 6)
    fmt.Printf("Updated: %+v\n", p)

    // ---- DELETE ----
    fmt.Println("\n=== DELETE ===")
    err = repo.Delete(2)
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("Deleted player with ID 2")

    // ---- Final read ----
    players, _ = repo.GetAll()
    fmt.Println("\nFinal players:")
    for _, p := range players {
        fmt.Printf("  %+v\n", p)
    }
}

