package main

import (
    "database/sql"
    "fmt"
    "log"

    _ "github.com/mattn/go-sqlite3"
)

type Product struct {
    ID    int
    Name  string
    Price float64
}

type ProductRepo struct {
    db *sql.DB
}

func NewProductRepo(db *sql.DB) *ProductRepo {
    return &ProductRepo{db: db}
}

func (r *ProductRepo) Create(name string, price float64) (Product, error) {
    res, err := r.db.Exec("INSERT INTO products (name, price) VALUES (?, ?)", name, price)
    if err != nil {
        return Product{}, err
    }
    id, _ := res.LastInsertId()
    return r.GetByID(int(id))
}

func (r *ProductRepo) GetAll() ([]Product, error) {
    rows, err := r.db.Query("SELECT id, name, price FROM products")
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    products := []Product{}
    for rows.Next() {
        var p Product
        rows.Scan(&p.ID, &p.Name, &p.Price)
        products = append(products, p)
    }
    return products, nil
}

func (r *ProductRepo) GetByID(id int) (Product, error) {
    var p Product
    err := r.db.QueryRow("SELECT id, name, price FROM products WHERE id = ?", id).Scan(&p.ID, &p.Name, &p.Price)
    return p, err
}

func (r *ProductRepo) Update(id int, name string, price float64) (Product, error) {
    _, err := r.db.Exec("UPDATE products SET name = ?, price = ? WHERE id = ?", name, price, id)
    if err != nil {
        return Product{}, err
    }
    return r.GetByID(id)
}

func (r *ProductRepo) Delete(id int) error {
    _, err := r.db.Exec("DELETE FROM products WHERE id = ?", id)
    return err
}

func main() {
    db, err := sql.Open("sqlite3", "./products.db")
    if err != nil {
        log.Fatal(err)
    }
    defer db.Close()

    db.Exec(`CREATE TABLE IF NOT EXISTS products (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT,
        price REAL
    )`)

    repo := NewProductRepo(db)

    p1, _ := repo.Create("Sword", 50.0)
    p2, _ := repo.Create("Shield", 40.0)

    fmt.Println("Created:", p1, p2)

    products, _ := repo.GetAll()
    fmt.Println("All:", products)

    p1, _ = repo.Update(p1.ID, "Iron Sword", 55.0)
    fmt.Println("Updated:", p1)

    repo.Delete(p2.ID)

    products, _ = repo.GetAll()
    fmt.Println("Final:", products)
}
